module half_adder (
    input A,
    input B,
    output SUM,
    output CARRY_OUT
);

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // XOR gate for SUM
    wire __SUM_tmp = A ^ B;
    assign SUM = __SUM_tmp;

    // AND gate for CARRY_OUT
    assign CARRY_OUT = A & B;

endmodule
